using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class EstimatesTraining : TrainingContentBase
{
    public EstimatesTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates Overview",
            Slug = "estimates-overview",
            Summary = "What estimates are, how they differ from quotes, their non-binding nature, and how to convert them into formal quotes.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers"]""",
            ContentJson = """{"body":"## Estimates Overview\n\nEstimates are non-binding ballpark figures you provide to customers before committing to a formal quote. They give customers a rough idea of cost without locking your shop into a fixed price. Estimates live inside the customer detail page on the Estimates tab — they are always tied to a specific customer.\n\n### Estimates vs Quotes\n\nEstimates and quotes serve different purposes in the sales pipeline:\n\n- **Estimate** — A single dollar amount with a title and optional description. Non-binding. Not line-itemized. Think of it as 'here's roughly what this would cost.' Stored in the quotes table with type = Estimate.\n- **Quote** — A binding, fixed-price commitment with individual line items (part, quantity, unit price). Line-itemized. Can be converted to a Sales Order. Stored in the quotes table with type = Quote.\n\nBecause estimates are intentionally simple, they have just one amount field — no line items, no tax calculations, no shipping addresses. This keeps the workflow fast when a customer calls and asks 'how much would it cost to make 500 of these?'\n\n### The Estimate Lifecycle\n\nEvery estimate starts in **Draft** status and moves through a straightforward lifecycle:\n\n1. **Draft** — Just created, still being refined. You can edit the title, amount, description, and notes freely.\n2. **Sent** — You've shared the estimate with the customer (via email, PDF, or verbally). The estimate is still editable.\n3. **Accepted** — The customer agreed to move forward based on the ballpark figure.\n4. **Declined** — The customer decided not to proceed.\n5. **Expired** — The estimate passed its Valid Until date without a decision.\n6. **Converted to Quote** — The estimate was converted into a formal, line-itemized quote. The estimate record is preserved with a link to the generated quote.\n\n### Converting to a Quote\n\nWhen a customer accepts an estimate and wants to move forward, you convert it to a formal quote. Click the forward arrow icon on the estimate row and confirm. This:\n\n- Creates a new Quote (type = Quote) in Draft status with an auto-generated quote number\n- Carries over the customer, notes, and expiration date\n- Sets the estimate's status to Converted to Quote\n- Records the conversion timestamp\n- Links the new quote back to the source estimate via the source_estimate_id field\n\nThe new quote starts empty (no line items) — you'll add parts, quantities, and pricing on the Quotes page. The estimate's single amount was just a ballpark; the quote is where you get precise.\n\n### When to Use Estimates\n\n- When a customer asks for a rough cost before you've done detailed engineering\n- When you want to qualify a lead before investing time in a full quote\n- When you need a fast turnaround on pricing (estimates take seconds to create)\n- When the scope is still being defined and line items aren't known yet\n\n### Where to Find Estimates\n\nEstimates are accessed through the customer detail page. Navigate to Customers, select a customer, then click the Estimates tab. All estimates for that customer are listed in a sortable, filterable data table. You can create, edit, convert, and delete estimates directly from this tab.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates — Guided Tour",
            Slug = "estimates-walkthrough",
            Summary = "A guided tour of creating and managing estimates via the customer detail Estimates tab.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers","walkthrough"]""",
            ContentJson = """{"appRoute":"/customers","startButtonLabel":"Tour Estimates","steps":[{"element":"app-data-table","popover":{"title":"Customer List","description":"Start by selecting a customer. Click any row to open the customer detail page where you can manage their estimates, quotes, orders, and more.","side":"top"}},{"element":"[data-testid='new-customer-btn']","popover":{"title":"Create Customer","description":"Before creating estimates, you need a customer. Click here to add one.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Customers","description":"Browse customers to access their estimates. Search by name, company, email, or phone, then click a customer row to open their detail page and navigate to the Estimates tab.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates Field Reference",
            Slug = "estimates-field-reference",
            Summary = "Complete reference for every field, status, action, and validation rule in the Estimates feature.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers","reference"]""",
            ContentJson = """{"title":"Estimates Field Reference","groups":[{"heading":"Estimate Form Fields","items":[{"label":"Title (required)","value":"Text input, max 300 characters. Identifies the estimate. Examples: 'CNC Bracket Prototype — 500 pcs', 'Tooling for Widget Housing'. Must not be empty."},{"label":"Description","value":"Textarea, optional, max 2000 characters. Longer explanation of what the estimate covers — assumptions, scope, exclusions."},{"label":"Estimated Amount (required)","value":"Currency input with $ prefix. The single ballpark dollar figure. Must be zero or greater. Not line-itemized — that detail comes in the formal quote."},{"label":"Valid Until","value":"Datepicker, optional. Expiration date for the estimate. After this date the estimate is considered expired if the customer hasn't responded."},{"label":"Status (edit only)","value":"Dropdown, shown only when editing an existing estimate. Options: Draft, Sent, Accepted, Declined, Expired. Not shown on create (defaults to Draft). ConvertedToQuote is set automatically by the conversion action."},{"label":"Notes","value":"Textarea, optional, max 2000 characters. Internal notes — assumptions, material considerations, follow-up reminders."}]},{"heading":"Estimate Statuses","items":[{"label":"Draft (gray chip)","value":"Initial status. Estimate is being prepared. Fully editable."},{"label":"Sent (blue chip)","value":"Estimate has been shared with the customer. Still editable."},{"label":"Accepted (green chip)","value":"Customer agreed to proceed based on this ballpark figure."},{"label":"Declined (red chip)","value":"Customer decided not to proceed."},{"label":"Expired (yellow chip)","value":"Estimate passed its Valid Until date without a customer decision."},{"label":"Converted to Quote (purple chip)","value":"Estimate was converted into a formal, line-itemized quote. Set automatically by the Convert action. The generated quote ID is linked."}]},{"heading":"Actions","items":[{"label":"New Estimate (primary button)","value":"Opens the create dialog. Fields: Title, Description, Estimated Amount, Valid Until, Notes. Saves in Draft status."},{"label":"Row click","value":"Opens the edit dialog pre-filled with the estimate's current values. The Status dropdown appears in edit mode."},{"label":"Convert to Quote (forward arrow icon)","value":"Creates a new formal Quote (type=Quote) in Draft status from this estimate. Sets the estimate's status to ConvertedToQuote. Carries over customer, notes, and expiration date. The new quote starts with no line items — add them on the Quotes page. Only available if the estimate hasn't already been converted."},{"label":"Delete (trash icon)","value":"Soft-deletes the estimate after confirmation. Shows a danger confirmation dialog with the estimate title."},{"label":"Save (dialog button)","value":"Creates or updates the estimate. Disabled when form is invalid or save is in progress. Hover shows validation popover listing violations."},{"label":"Cancel (dialog button)","value":"Closes the dialog without saving."}]},{"heading":"Table Columns","items":[{"label":"Title","value":"Sortable. The estimate's title text."},{"label":"Amount","value":"Sortable (number type). Right-aligned. Displayed as formatted currency (e.g., $12,500.00)."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip: Draft (gray), Sent (blue), Accepted (green), Declined (red), Expired (yellow), ConvertedToQuote (purple)."},{"label":"Valid Until","value":"Sortable (date type). Displayed as MM/dd/yyyy. Blank if no expiration set."},{"label":"Created","value":"Sortable (date type). Displayed as MM/dd/yyyy. When the estimate was first created."},{"label":"Actions","value":"Not sortable. Contains Convert to Quote (forward arrow, hidden if already converted) and Delete (trash icon) buttons."}]},{"heading":"Validation Rules","items":[{"label":"Title","value":"Required. Max 300 characters. Cannot be empty."},{"label":"Estimated Amount","value":"Required. Must be a number >= 0. Currency mask applied."},{"label":"Description","value":"Optional. Max 2000 characters when provided."},{"label":"Notes","value":"Optional. Max 2000 characters when provided."},{"label":"Valid Until","value":"Optional. No past-date restriction — you can backdate if needed."},{"label":"Convert to Quote","value":"Only available if the estimate has not already been converted (no generatedQuoteId). Confirmation dialog required."},{"label":"Delete","value":"Confirmation dialog required (danger severity). Soft-delete — record preserved in database."}]},{"heading":"Navigation & Access","items":[{"label":"Location","value":"Customers page → select customer → Estimates tab. Estimates are always scoped to a single customer."},{"label":"Related features","value":"Quotes (formal, line-itemized commitments), Sales Orders (created from accepted quotes), Customer detail (parent page)."},{"label":"Data storage","value":"Estimates are stored in the quotes table with type=Estimate. They share the table with formal quotes but have different fields populated."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Estimates Knowledge Check",
            Slug = "estimates-quiz",
            Summary = "Test your knowledge of the Estimates feature: purpose, lifecycle, conversion to quotes, and field details.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/customers"]""",
            Tags = """["estimates","customers","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"est1","text":"A customer calls and asks 'roughly how much would 500 aluminum brackets cost?' You don't have detailed engineering yet. What should you create in QB Engineer?","options":[{"id":"a","text":"A Quote with a single line item for 500 brackets"},{"id":"b","text":"A Sales Order with an estimated total"},{"id":"c","text":"An Estimate on the customer's Estimates tab with the ballpark amount","isCorrect":true},{"id":"d","text":"A Job on the Kanban board tagged as 'pricing'"}],"explanation":"Estimates are designed for exactly this scenario — providing a quick, non-binding ballpark figure before you've done detailed engineering. Create one on the customer's Estimates tab with a title and dollar amount."},{"id":"est2","text":"What is the key difference between an estimate and a quote in QB Engineer?","options":[{"id":"a","text":"Estimates require manager approval; quotes do not"},{"id":"b","text":"Estimates are a single non-binding amount; quotes are binding with individual line items (part, quantity, unit price)","isCorrect":true},{"id":"c","text":"Estimates can only be created by Admin users; quotes by anyone"},{"id":"d","text":"Estimates are emailed automatically; quotes must be printed"}],"explanation":"Estimates are intentionally simple — a single dollar amount, non-binding, no line items. Quotes are formal, binding commitments broken into line items with parts, quantities, and unit pricing."},{"id":"est3","text":"Where do you find and manage estimates in QB Engineer?","options":[{"id":"a","text":"On a dedicated Estimates page in the main navigation"},{"id":"b","text":"On the customer detail page, under the Estimates tab","isCorrect":true},{"id":"c","text":"In the Quotes module, filtered by type"},{"id":"d","text":"On the Dashboard under the Sales widget"}],"explanation":"Estimates are accessed through the customer detail page. Navigate to Customers, select a customer, then click the Estimates tab. All estimates for that customer are listed there."},{"id":"est4","text":"You created an estimate last week and the customer just said they want to proceed. What is the next step?","options":[{"id":"a","text":"Change the estimate's status to Accepted, then create a Sales Order manually"},{"id":"b","text":"Delete the estimate and create a Quote from scratch"},{"id":"c","text":"Click the Convert to Quote icon on the estimate row — it creates a new formal quote linked to the estimate","isCorrect":true},{"id":"d","text":"Edit the estimate to add line items and convert it in place"}],"explanation":"Click the forward arrow icon on the estimate row to convert it. This creates a new Quote (type=Quote) in Draft status, sets the estimate to ConvertedToQuote, and links them together. You then add line items to the new quote."},{"id":"est5","text":"What happens to an estimate after it is converted to a quote?","options":[{"id":"a","text":"The estimate is deleted and replaced by the quote"},{"id":"b","text":"The estimate's status changes to ConvertedToQuote, and it links to the new quote. The estimate record is preserved.","isCorrect":true},{"id":"c","text":"The estimate becomes editable again so you can update the amount"},{"id":"d","text":"The estimate is archived and hidden from the Estimates tab"}],"explanation":"The estimate is preserved with its status set to ConvertedToQuote and a conversion timestamp. It maintains a link to the generated quote via the generatedQuoteId field. You can still see it in the Estimates tab."},{"id":"est6","text":"Which fields are required when creating a new estimate?","options":[{"id":"a","text":"Title, Description, Estimated Amount, and Valid Until date"},{"id":"b","text":"Title and Estimated Amount only","isCorrect":true},{"id":"c","text":"Title, Estimated Amount, Status, and Assigned To"},{"id":"d","text":"Only the Estimated Amount — everything else is optional"}],"explanation":"Only two fields are required: Title (max 300 characters) and Estimated Amount (must be >= 0). Description, Valid Until, and Notes are all optional."},{"id":"est7","text":"An estimate shows a yellow 'Expired' status chip. What does this mean?","options":[{"id":"a","text":"The estimate was rejected by the customer"},{"id":"b","text":"The estimate passed its Valid Until date without a customer decision","isCorrect":true},{"id":"c","text":"The estimate has been converted to a quote"},{"id":"d","text":"The estimate was created more than 30 days ago"}],"explanation":"Expired (yellow chip) means the estimate passed its Valid Until date without the customer accepting or declining. You can still edit the estimate and extend the date if needed."},{"id":"est8","text":"A new quote was created from an estimate conversion. What state does the new quote start in?","options":[{"id":"a","text":"Draft status with no line items — you need to add parts, quantities, and pricing","isCorrect":true},{"id":"b","text":"Sent status with the estimate amount as a single line item"},{"id":"c","text":"Accepted status since the customer already agreed to the estimate"},{"id":"d","text":"Draft status with line items auto-populated from the estimate description"}],"explanation":"The converted quote starts in Draft status with no line items. The estimate was just a ballpark — the quote is where you add precise line-item pricing (parts, quantities, unit prices). Only the customer, notes, and expiration date carry over."},{"id":"est9","text":"You want to delete an estimate that was entered by mistake. What happens?","options":[{"id":"a","text":"The estimate is permanently removed from the database"},{"id":"b","text":"The estimate is soft-deleted — the record is preserved in the database but hidden from the UI. A confirmation dialog appears first.","isCorrect":true},{"id":"c","text":"The estimate moves to a Trash folder where it can be restored within 30 days"},{"id":"d","text":"You cannot delete estimates — you can only change their status to Declined"}],"explanation":"Deleting an estimate triggers a danger confirmation dialog. On confirmation, the record is soft-deleted (DeletedAt timestamp set) — it's preserved in the database for audit purposes but no longer visible in the Estimates tab."},{"id":"est10","text":"Can you convert the same estimate to a quote more than once?","options":[{"id":"a","text":"Yes — each conversion creates an additional quote linked to the same estimate"},{"id":"b","text":"No — once an estimate has been converted, the Convert to Quote button is hidden and the API prevents duplicate conversion","isCorrect":true},{"id":"c","text":"Yes, but only if the first generated quote was deleted"},{"id":"d","text":"No — you must create a new estimate to generate another quote"}],"explanation":"An estimate can only be converted once. The Convert to Quote icon is hidden for estimates that already have a generatedQuoteId. The API also validates this — if the estimate already has a generated quote, it throws an error: 'Estimate has already been converted to a quote.'"}]}"""
        });

        Log.Information("Seeded Estimates training modules");
    }
}
